			System.setProperty(MEMO_FLAG, "true");
			long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
			long memoBefore = memoMaterializations();
			assertThat(rows(query)).as("native memo enabled vs generic for:\n" + query).isEqualTo(generic);
			assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
					.as("native compiler should accept:\n" + query)
					.isGreaterThan(compiledBefore);
			assertThat(memoMaterializations())
					.as("repeated correlation key should materialize right side once:\n" + query)
					.isGreaterThan(memoBefore);
